<?php
 namespace WPAICG\AutoGPT\Cron\Scheduler\Schedule; require_once __DIR__ . '/get-task-specific-cron-hook.php'; require_once __DIR__ . '/clear-task-event.php'; require_once __DIR__ . '/../utils/get-current-cron-event-details.php'; if (!defined('ABSPATH')) { exit; } function schedule_task_event_logic(int $task_id, string $frequency, string $status): void { global $wpdb; $tasks_table_name = $wpdb->prefix . 'aipkit_automated_tasks'; $hook = get_task_specific_cron_hook_logic($task_id); $current_schedule_args = [$task_id]; $event_details = \WPAICG\AutoGPT\Cron\Scheduler\Utils\get_current_cron_event_details_logic($hook, $current_schedule_args); $current_event_timestamp = $event_details['timestamp']; $current_frequency = $event_details['frequency']; if ($status === 'active') { $should_reschedule = ($current_event_timestamp === false || $current_frequency !== $frequency); if ($should_reschedule) { wp_clear_scheduled_hook($hook, $current_schedule_args); if ($frequency === 'one-time') { wp_schedule_single_event(time() + 10, $hook, $current_schedule_args); } else { wp_schedule_event(time() + (MINUTE_IN_SECONDS / 2), $frequency, $hook, $current_schedule_args); } } $next_run_timestamp = wp_next_scheduled($hook, $current_schedule_args); $next_run_datetime_gmt = $next_run_timestamp ? gmdate('Y-m-d H:i:s', $next_run_timestamp) : null; $wpdb->update( $tasks_table_name, ['next_run_time' => $next_run_datetime_gmt], ['id' => $task_id], ['%s'], ['%d'] ); } else { clear_task_event_logic($task_id); } } 